#include <stdio.h>
int main() {
    int T, n, k;
    scanf("%d %d", &T, &n);
    while (T--) {
        scanf("%d", &k);
        int map[n][n];
        for (int i = 0; i < n; i++) {
            for (int j = 0; j < n; j++) {
                scanf("%d", &map[i][j]);
            }
        }
        for (int i = 0; i <= n - k; i++) {
            for (int j = 0; j <= n - k; j++) {
                int min = map[i][j];
                for (int x = 0; x < k; x++) {
                    for (int y = 0; y < k; y++) {
                        if (map[i + x][j + y] < min) {
                            min = map[i + x][j + y];
                        }
                    }
                }
                printf("%d ", min);
            }
            printf("\n");
        }
    }
    return 0;
}

