import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int n = sc.nextInt();
            int k = sc.nextInt();
            int[][] map = new int[n][n];
            for (int i = 0; i < n; i++) {
                for (int j = 0; j < n; j++) {
                    map[i][j] = sc.nextInt();
                }
            }
            for (int i = 0; i <= n - k; i++) {
                for (int j = 0; j <= n - k; j++) {
                    int min = map[i][j];
                    for (int x = 0; x < k; x++) {
                        for (int y = 0; y < k; y++) {
                            if (map[i + x][j + y] < min) {
                                min = map[i + x][j + y];
                            }
                        }
                    }
                    System.out.print(min + " ");
                }
                System.out.println();
            }
        }
    }
}

