const lines = require('fs').readFileSync(0, 'utf-8').trim().split('\n');
let i = 0;
const readline = () => lines[i++];
const [T, n] = readline().split(' ').map(Number);
for (let t = 0; t < T; t++) {
    const k = parseInt(readline());
    const map = [];
    for (let i = 0; i < n; i++) {
        map.push(readline().split(' ').map(Number));
    }
    for (let i = 0; i <= n - k; i++) {
        for (let j = 0; j <= n - k; j++) {
            let min = map[i][j];
            for (let x = 0; x < k; x++) {
                for (let y = 0; y < k; y++) {
                    if (map[i + x][j + y] < min) {
                        min = map[i + x][j + y];
                    }
                }
            }
            process.stdout.write(min + ' ');
        }
        process.stdout.write('\n');
    }
}
